using System;
using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

class PropertyEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext context)
        => UITypeEditorEditStyle.DropDown;

    public override object EditValue(ITypeDescriptorContext context, IServiceProvider provider, object value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService is null) return value;

        var control = CreateDropDownControl(value);

        // .NET 9 breaking change: DropDownControl(null) now throws ArgumentNullException.
        // Use CloseDropDown() when there is no control to display.
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = (control as ListBox)?.SelectedItem ?? value;
        }
        else
        {
            editorService.CloseDropDown();
        }

        return value;
    }

    private static Control CreateDropDownControl(object value)
    {
        if (value is not string s) return null;
        var listBox = new ListBox();
        listBox.Items.Add(s);
        return listBox;
    }
}

